const http = require('node:http');

const PORT = process.env.PORT || 3000;
const MONITOR_URL = 'http://monitor.internal:8080/ping';
const REQUEST_TIMEOUT_MS = 3000;

async function pingMonitor() {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

  try {
    const response = await fetch(MONITOR_URL, {
      signal: controller.signal,
      cache: 'no-store',
    });

    const body = await response.text();
    return {
      ok: response.ok,
      status: response.status,
      body,
    };
  } finally {
    clearTimeout(timeout);
  }
}

const server = http.createServer(async (req, res) => {
  if (req.method === 'GET' && req.url === '/health') {
    try {
      const monitor = await pingMonitor();
      res.writeHead(monitor.ok ? 200 : 502, {
        'Content-Type': 'application/json; charset=utf-8',
      });
      res.end(
        JSON.stringify({
          status: monitor.ok ? 'ok' : 'degraded',
          monitor: {
            url: MONITOR_URL,
            status: monitor.status,
          },
        }),
      );
    } catch (error) {
      const reason = error && error.name === 'AbortError' ? 'timeout' : 'unreachable';
      res.writeHead(502, {
        'Content-Type': 'application/json; charset=utf-8',
      });
      res.end(
        JSON.stringify({
          status: 'degraded',
          monitor: {
            url: MONITOR_URL,
            status: reason,
          },
        }),
      );
    }
    return;
  }

  res.writeHead(404, { 'Content-Type': 'text/plain; charset=utf-8' });
  res.end('Not Found');
});

server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

